import{_ as t,o as n,c as r,ag as i}from"./chunks/framework.CvgP6Fyv.js";const b=JSON.parse('{"title":"Objekte & Vermögenswerte","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/objects.md","filePath":"de/features/objects.md"}'),a={name:"de/features/objects.md"};function s(l,e,o,d,u,g){return n(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="objekte-vermogenswerte" tabindex="-1">Objekte &amp; Vermögenswerte <a class="header-anchor" href="#objekte-vermogenswerte" aria-label="Permalink to &quot;Objekte &amp; Vermögenswerte&quot;">​</a></h1><p>Verfolgen Sie Mietobjekte, Fahrzeuge, Ausstattung und andere Geschäftsvermögenswerte mit vollständigem Lebenszyklus-Management.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Das Objektmodul ist optional. Aktivieren Sie es unter <strong>Unternehmen &gt; Funktionen</strong>, wenn Sie es nicht in der Navigation sehen.</p></div><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Das Objektmodul ist für Unternehmen konzipiert, die physische Vermögenswerte verwalten — insbesondere Vermietungsunternehmen, Immobilienverwalter und Geräteverleihdienste. Jedes Objekt repräsentiert einen Vermögenswert, den Sie besitzen oder verwalten.</p><h2 id="objekttypen" tabindex="-1">Objekttypen <a class="header-anchor" href="#objekttypen" aria-label="Permalink to &quot;Objekttypen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Typ</th><th>Anwendungsfall</th></tr></thead><tbody><tr><td><strong>Immobilie</strong></td><td>Mietwohnungen, Büros, Gewerbeflächen</td></tr><tr><td><strong>Fahrzeug</strong></td><td>PKW, LKW, Transporter, Baufahrzeuge</td></tr><tr><td><strong>Maschine</strong></td><td>Industrieausrüstung, Werkzeuge, Generatoren</td></tr><tr><td><strong>Sonstiges</strong></td><td>Jeder andere Vermögenswerttyp</td></tr></tbody></table><h2 id="objektstatus" tabindex="-1">Objektstatus <a class="header-anchor" href="#objektstatus" aria-label="Permalink to &quot;Objektstatus&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Verfügbar</strong></td><td>Bereit zur Vermietung oder Nutzung</td></tr><tr><td><strong>Vermietet</strong></td><td>Derzeit an einen Kunden vermietet</td></tr><tr><td><strong>Inaktiv</strong></td><td>Nicht verfügbar (Wartung, ausgemustert)</td></tr></tbody></table><h2 id="objekt-erstellen" tabindex="-1">Objekt erstellen <a class="header-anchor" href="#objekt-erstellen" aria-label="Permalink to &quot;Objekt erstellen&quot;">​</a></h2><ol><li>Gehen Sie zu <strong>Objekte &gt; Neues Objekt</strong></li><li>Füllen Sie aus: <ul><li><strong>Name</strong> — Eine eindeutige Bezeichnung (z. B. „Wohnung 3B&quot; oder „Bagger CAT 320&quot;)</li><li><strong>Typ</strong> — Immobilie, Fahrzeug, Maschine oder Sonstiges</li><li><strong>Status</strong> — Verfügbar, Vermietet oder Inaktiv</li><li><strong>Beschreibung</strong> — Details zum Vermögenswert</li></ul></li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><h2 id="objektdetailseite" tabindex="-1">Objektdetailseite <a class="header-anchor" href="#objektdetailseite" aria-label="Permalink to &quot;Objektdetailseite&quot;">​</a></h2><p>Die Detailseite zeigt:</p><ul><li>Vermögenswertinformationen und Typ</li><li>Aktueller Status</li><li>Verknüpfte Verträge</li><li>Mietverlauf</li><li>Zugehörige Rechnungen</li></ul><h2 id="objekte-mit-vertragen-und-rechnungen-verknupfen" tabindex="-1">Objekte mit Verträgen und Rechnungen verknüpfen <a class="header-anchor" href="#objekte-mit-vertragen-und-rechnungen-verknupfen" aria-label="Permalink to &quot;Objekte mit Verträgen und Rechnungen verknüpfen&quot;">​</a></h2><p>Objekte lassen sich mit anderen MyCompanyDesk-Funktionen integrieren:</p><ul><li><strong>Verträge</strong> — Erstellen Sie einen Mietvertrag für ein Objekt mit Angabe des Mieters (Kunden) und der Bedingungen</li><li><strong>Rechnungen</strong> — Rechnungen können als Mietrechnungen gekennzeichnet und mit Objekten verknüpft werden</li><li><strong>Wiederkehrende Rechnungen</strong> — Richten Sie automatische monatliche Mietabrechnungen pro Objekt ein</li></ul><h2 id="filtern" tabindex="-1">Filtern <a class="header-anchor" href="#filtern" aria-label="Permalink to &quot;Filtern&quot;">​</a></h2><p>Filtern Sie Ihre Objekte nach:</p><ul><li><strong>Typ</strong> — Immobilie, Fahrzeug, Maschine, Sonstiges</li><li><strong>Status</strong> — Verfügbar, Vermietet, Inaktiv</li><li><strong>Suche</strong> — Nach Name oder Beschreibung finden</li></ul><h2 id="massenaktionen" tabindex="-1">Massenaktionen <a class="header-anchor" href="#massenaktionen" aria-label="Permalink to &quot;Massenaktionen&quot;">​</a></h2><ul><li><strong>Status ändern</strong> — Verfügbarkeit in großem Umfang aktualisieren</li><li><strong>Archivieren</strong> — Ins Archiv verschieben</li><li><strong>Löschen</strong> — Objekte entfernen</li></ul><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Verwenden Sie den Statusfilter, um schnell zu sehen, welche Vermögenswerte zur Vermietung verfügbar sind</li><li>Verknüpfen Sie jede Mietrechnung mit ihrem Objekt für eine vollständige finanzielle Nachverfolgung pro Vermögenswert</li><li>Richten Sie Verträge mit Wiederholung für automatische Mietabrechnung ein</li><li>Prüfen Sie die Objektkennzahlen oben auf der Seite für einen Verfügbarkeitsüberblick</li></ul>',24)])])}const c=t(a,[["render",s]]);export{b as __pageData,c as default};
